INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (1011, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。", 1, 1, 1);
INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (1021, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。", 2, 2, 1);
INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (1041, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 4, 4, 1);
INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (1051, "ボスバトルには３種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。", 5, 5, 1);
INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (2011, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。", 1, 1, 2);
INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (2021, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。", 2, 2, 2);
INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (2041, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 4, 4, 2);
INSERT INTO `v1_44f37f4f36162752419e35fe40bcc075f8fed4f9e3d82b8db9b0b82459e78119` VALUES (2051, "ボスバトルには２種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。", 5, 5, 2);
